            {/* Right antenna tilt-line */}
            <path data-cux-antenna="right" fill="#00EAAB" d="M755.315 301.629C761.377 309.16 761.169 315.093 754.6 321.717C745.226 331.168 735.773 340.542 726.27 349.863C720.095 355.921 712.048 355.947 706.295 350.114C701.055 344.803 701.353 336.882 707.198 330.961C716.668 321.369 726.156 311.793 735.787 302.363C741.764 296.511 748.167 296.322 755.315 301.629Z" />

